SELECT team_id, COUNT(score) AS number_of_races, SUM(score) AS total_score
FROM event_scores
GROUP BY team_id;

SELECT COUNT(relay_team_id) 
FROM relay_teams 
WHERE race_id = 1;

SELECT DISTINCT t.coach_name, t.contact_email
FROM teams t
JOIN relay_teams rt ON t.team_id = rt.team_id;

SELECT race_id, COUNT(athlete_id) AS num_athletes
FROM athlete_performance
GROUP BY race_id;

SELECT athlete_id, performance_time
FROM athlete_performance
ORDER BY performance_time ASC;

SELECT score
FROM relay_teams
WHERE score > 5;
